// IReader defines a type that can read bytes.
type IReader interface {
	Read(p []byte) (n int, err error)
}

// IWriter defines a type that can write bytes.
type IWriter interface {
	Write(p []byte) (n int, err error)
}

// ICloser defines a type that can be closed.
type ICloser interface {
	Close() error
}
